config.options.plugins.legend = {
  onHover: (evt, chartElement) => {
    evt.native.target.style.cursor = 'pointer';
  },
  onLeave: (evt, chartElement) => {
    evt.native.target.style.cursor = 'default';
  },
  position: 'bottom',
  display: true,
  labels: {
