            fillStyle: 'transparent',
            fontColor: '#666',
            lineWidth: 0,
            datasetIndex: -1, // Special index to identify period label
          };

          // Return period label followed by dataset labels
          return [
            periodLabel,
            ...data.datasets.map((dataset, i) => ({
              text: dataset.label,
              fillStyle: chart.isDatasetVisible(i) ? dataset.borderColor : 'lightgray',
              fontColor: visibility[i],
              lineWidth: 0,
              datasetIndex: i,
            }))
          ];
