        fontColor: visibility[i],
        lineWidth: 0,
        datasetIndex: i,
      }));
    },
  },
};
```

You'll also need to add a translation key for the period label:

```javascript
// In your translations file
{
  "VisualizationGraph": {
    "period": "Period"
    // ... other translations
  }
}
```

This will add a period label at the top of the legend showing the start and end dates of the data. The dates will be formatted according to the `groupBy` setting. The period label will be styled differently from the dataset labels (no color box) to distinguish it from the actual data series.

To ensure the period label doesn't interfere with the chart's click handling, you might also want to update the chart's click handlers to check for the special `datasetIndex` of -1:

```javascript
onClick: (evt, elements, chart) => {
  if (evt.type === 'click' && elements[0]) {
    const index = elements[0].datasetIndex;
    // Only handle clicks on actual datasets, not the period label
    if (index !== -1) {
      // Your existing click handling code
    }
  }
}
```

This modification will show the period of the data at the top of the legend while maintaining all existing functionality of the legend and chart.
